'use client';

import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import { z } from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { List, Check } from 'lucide-react';
import { Textarea } from '../ui/textarea';
import React from 'react';
import { useCurrencySymbol } from '@/hooks/use-currency';
import { cn } from '@/lib/utils';
import { categories } from '@/lib/data';
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from '@/components/ui/command';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover';

const formSchema = z.object({
  type: z.enum(['income', 'expense']),
  amount: z.coerce.number().positive('Amount must be positive'),
  categoryName: z.string().min(1, 'Category is required'),
  description: z.string().optional(),
});

type AddTransactionProps = {
  children?: React.ReactNode;
  defaultType?: 'income' | 'expense';
};

export function AddTransactionSheet({ 
  children, 
  defaultType = 'expense' 
}: AddTransactionProps) {
  const currencySymbol = useCurrencySymbol();
  const [open, setOpen] = React.useState(false);
  const [categoryPopoverOpen, setCategoryPopoverOpen] = React.useState(false);

  const form = useForm<z.infer<typeof formSchema>>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      type: defaultType,
      amount: 0,
      categoryName: '',
      description: '',
    },
  });

  const selectedType = form.watch('type');
  
  // Filter categories based on transaction type
  const availableCategories = categories.filter(c => c.type === selectedType);

  function onSubmit(values: z.infer<typeof formSchema>) {
    console.log('Saving transaction:', values);
    // In a real app, this would be a Firestore addDoc call
    setOpen(false);
    form.reset();
  }

  const title = selectedType === 'income' ? 'Add Income' : 'Add Expense';

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        {children}
      </DialogTrigger>
      <DialogContent className="sm:max-w-[500px] p-0 overflow-hidden rounded-[2.5rem] border-0 shadow-2xl">
        <DialogHeader className="px-10 pt-10 flex flex-row items-center justify-between space-y-0">
          <DialogTitle className="text-3xl font-bold bg-gradient-to-tr from-primary to-accent bg-clip-text text-transparent">
            {title}
          </DialogTitle>
        </DialogHeader>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="px-10 pb-10 space-y-6 pt-6">
            {/* Category Field */}
            <FormField
              control={form.control}
              name="categoryName"
              render={({ field }) => (
                <FormItem className="space-y-2">
                  <FormLabel className="text-sm font-bold text-[#334155] uppercase tracking-wider ml-1">Category</FormLabel>
                  <div className="relative">
                    <FormControl>
                      <Input 
                        placeholder="Enter category name" 
                        className="rounded-xl h-14 border-[#cbd5e1] focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all pr-14"
                        {...field} 
                      />
                    </FormControl>
                    <Popover open={categoryPopoverOpen} onOpenChange={setCategoryPopoverOpen}>
                      <PopoverTrigger asChild>
                        <button 
                          type="button"
                          className="absolute right-2 top-1/2 -translate-y-1/2 flex items-center justify-center h-10 w-10 rounded-lg text-[#64748b] hover:bg-muted transition-colors z-10"
                        >
                          <List className="h-5 w-5" />
                        </button>
                      </PopoverTrigger>
                      <PopoverContent className="w-[240px] p-0 rounded-2xl shadow-xl border-muted" align="end">
                        <Command className="rounded-2xl">
                          <CommandInput placeholder="Search category..." className="h-12" />
                          <CommandList>
                            <CommandEmpty>No category found.</CommandEmpty>
                            <CommandGroup heading="Suggestions">
                              {availableCategories.map((category) => (
                                <CommandItem
                                  key={category.id}
                                  value={category.name}
                                  onSelect={() => {
                                    // Use the explicit category name to populate the field
                                    form.setValue('categoryName', category.name, { shouldValidate: true });
                                    setCategoryPopoverOpen(false);
                                  }}
                                  className="flex items-center gap-2 px-3 py-3 cursor-pointer hover:bg-muted"
                                >
                                  <div className="flex items-center justify-center w-8 h-8 rounded-full bg-primary/5 text-primary">
                                     <category.icon className="h-4 w-4" />
                                  </div>
                                  <span className="font-medium text-[#334155]">{category.name}</span>
                                  {field.value === category.name && (
                                    <Check className="ml-auto h-4 w-4 text-primary" />
                                  )}
                                </CommandItem>
                              ))}
                            </CommandGroup>
                          </CommandList>
                        </Command>
                      </PopoverContent>
                    </Popover>
                  </div>
                  <FormMessage className="ml-1" />
                </FormItem>
              )}
            />

            {/* Amount Field */}
            <FormField
              control={form.control}
              name="amount"
              render={({ field }) => (
                <FormItem className="space-y-2">
                  <FormLabel className="text-sm font-bold text-[#334155] uppercase tracking-wider ml-1">Amount</FormLabel>
                  <div className="flex group">
                    <div className="flex items-center justify-center px-5 border border-r-0 border-[#cbd5e1] rounded-l-xl bg-[#f8fafc] text-[#64748b] font-bold text-lg min-w-[4rem]">
                      {currencySymbol || '₹'}
                    </div>
                    <FormControl>
                      <Input 
                        type="number"
                        step="0.01"
                        placeholder="0.00" 
                        className="rounded-r-xl rounded-l-none h-14 border-[#cbd5e1] focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all text-lg font-medium"
                        {...field} 
                      />
                    </FormControl>
                  </div>
                  <FormMessage className="ml-1" />
                </FormItem>
              )}
            />

            {/* Description Field */}
            <FormField
              control={form.control}
              name="description"
              render={({ field }) => (
                <FormItem className="space-y-2">
                  <FormLabel className="text-sm font-bold text-[#334155] uppercase tracking-wider ml-1">Description (Optional)</FormLabel>
                  <FormControl>
                    <Textarea 
                      placeholder="Add a note for this transaction..." 
                      className="min-h-[100px] rounded-xl border-[#cbd5e1] focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all resize-none p-4"
                      {...field} 
                    />
                  </FormControl>
                  <FormMessage className="ml-1" />
                </FormItem>
              )}
            />

            <Button 
              type="submit" 
              className="w-full h-14 bg-gradient-to-tr from-primary to-accent hover:opacity-95 text-white font-bold text-lg rounded-2xl transition-all shadow-xl mt-4 border-0 active:scale-[0.98]"
            >
              Save Transaction
            </Button>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}
